#include<bits/stdc++.h>
using namespace std;
#define endl '\n'
int a[1002002],k=0;
bitset<1002002> b;
int main()
{
	int n,x,y;
	const int m=1002001;
	cin>>n>>x;
	for(int i=ceil((double)sqrt(n));i*i<=m;i++)
	{
		if(b[i*i]==0)
		{
			for(int j=1;i*i*j<=m;j++)
			{
				b[i*i*j]=1;
			}
		}
	}
	for(int i=1;i<=m;i++)
	{
		if(b[i]==1)
		{
			a[++k]=i;
		}
	}
	for(int i=1;i<=x;i++)
	{
		cin>>y;
		if(b[y]==1)
		{
			cout<<"lucky\n";
		}
		else
		{
			cout<<a[upper_bound(a+1,a+k+1,y)-a]<<endl;
		}
	}
}
